// Extract the prompt from the request
const input = $input.first().json.body || $input.first().json;

// Prepare data for Claude
return {
  prompt: input.prompt || "What is 2+2?",
  json: input.json || false,
  max_turns: input.max_turns || 1,
  test_case: input.test_case || null
};

// Process the response from Claude proxy
const response = $input.first().json;

let result = {
  success: response.success || false,
  prompt: $node["Prepare Claude Request"].json.prompt,
  response: response.stdout || "",
  error: response.stderr || "",
  command: response.command || ""
};

// Try to parse JSON if it looks like JSON
if (result.response && (result.response.startsWith('{') || result.response.startsWith('['))) {
  try {
    result.parsed_json = JSON.parse(result.response);
  } catch (e) {
    // Not valid JSON
  }
}

return result;
